#include <bits/stdc++.h>
using namespace std;
int n;
string s; 
int main(){
    int n;
    cin>>n;
    for(int i=0;i<n;i++){
    	cin>>s;
    	if(s==".-") cout<<"A";
    	else if(s=="-...") cout<<"B";
    	else if(s=="-.-.") cout<<"C";
    	else if(s=="-..") cout<<"D";
    	else if(s==".") cout<<"E";
    	else if(s=="..-.") cout<<"F";
    	else if(s=="--.") cout<<"G";
    	else if(s=="....") cout<<"H";
    	else if(s=="..") cout<<"I";
    	else if(s==".---") cout<<"J";
    	else if(s=="-.-") cout<<"K";
    	else if(s==".-..") cout<<"L";
    	else if(s=="--") cout<<"M";
    	else if(s=="-.") cout<<"N";
    	else if(s=="---") cout<<"O";
    	else if(s==".--.") cout<<"P";
    	else if(s=="--.-") cout<<"Q";
    	else if(s==".-.") cout<<"R";
    	else if(s=="...") cout<<"S";
    	else if(s=="-") cout<<"T";
    	else if(s=="..-") cout<<"U";
    	else if(s=="...-") cout<<"V";
    	else if(s==".--") cout<<"W";
    	else if(s=="-..-") cout<<"X";
    	else if(s=="-.--") cout<<"Y";
    	else if(s=="--..") cout<<"Z";
	}
	return 0;
}
